import React, { useContext, useEffect, useRef, useState } from 'react';
import { QuestionContext } from './QuestionContext';

// Simple image cropper canvas component
function ImageCropper({ dataUrl, onCrop }) {
  const canvasRef = useRef(null);
  const imgRef = useRef(null);
  const [rect, setRect] = useState(null);
  const dragging = useRef(false);
  const start = useRef([0, 0]);

  useEffect(() => {
    const img = new Image();
    img.src = dataUrl;
    img.onload = () => {
      imgRef.current = img;
      const canvas = canvasRef.current;
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0);
    };
  }, [dataUrl]);

  const redraw = () => {
    const img = imgRef.current;
    const canvas = canvasRef.current;
    if (!img || !canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0);
    if (rect) {
      ctx.strokeStyle = 'red';
      ctx.lineWidth = 2;
      ctx.strokeRect(rect.x, rect.y, rect.w, rect.h);
    }
  };

  useEffect(redraw, [rect]);

  const onDown = (e) => {
    const canvas = canvasRef.current;
    const rectCanvas = canvas.getBoundingClientRect();
    const x = e.clientX - rectCanvas.left;
    const y = e.clientY - rectCanvas.top;
    start.current = [x, y];
    dragging.current = true;
    setRect({ x, y, w: 0, h: 0 });
  };

  const onMove = (e) => {
    if (!dragging.current) return;
    const canvas = canvasRef.current;
    const rectCanvas = canvas.getBoundingClientRect();
    const x = e.clientX - rectCanvas.left;
    const y = e.clientY - rectCanvas.top;
    const sx = start.current[0];
    const sy = start.current[1];
    setRect({ x: Math.min(sx, x), y: Math.min(sy, y), w: Math.abs(x - sx), h: Math.abs(y - sy) });
  };

  const onUp = () => {
    dragging.current = false;
  };

  const handleCrop = () => {
    if (!rect) return;
    const canvas = document.createElement('canvas');
    canvas.width = rect.w;
    canvas.height = rect.h;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(imgRef.current, rect.x, rect.y, rect.w, rect.h, 0, 0, rect.w, rect.h);
    canvas.toBlob((b) => {
      const croppedUrl = URL.createObjectURL(b);
      onCrop(b, croppedUrl);
    }, 'image/png');
  };

  return (
    <div>
      <canvas ref={canvasRef} style={{ border: '1px solid #ccc', maxWidth: '100%' }} onMouseDown={onDown} onMouseMove={onMove} onMouseUp={onUp} />
      <div style={{ marginTop: 8 }}>
        <button type="button" onClick={handleCrop}>Crop Selection</button>
      </div>
    </div>
  );
}

export default function QuestionUploader({ onSetExtractedText }) {
  const API_BASE = process.env.REACT_APP_API_BASE || 'http://localhost:8000';
  const { questions, addOrUpdateQuestion, getQuestion } = useContext(QuestionContext);
  const [selectedQ, setSelectedQ] = useState('');
  const [files, setFiles] = useState([]); // {name, dataUrl}
  const [currentPreview, setCurrentPreview] = useState(null);
  const [message, setMessage] = useState('');

  useEffect(() => {
    if (questions.length > 0 && !selectedQ) setSelectedQ(questions[0].questionNumber);
  }, [questions]);

  // load per-question ocrText when selected changes
  useEffect(() => {
    if (!selectedQ) return;
    const q = getQuestion(selectedQ);
    if (q && q.ocrText) {
      onSetExtractedText(q.ocrText);
    }
  }, [selectedQ]);

  const handleFiles = (e) => {
    const list = Array.from(e.target.files);
    list.forEach((f) => {
      const reader = new FileReader();
      reader.onload = () => setFiles((cur) => [...cur, { name: f.name, dataUrl: reader.result }]);
      reader.readAsDataURL(f);
    });
  };

  const handleCropResult = (blob, croppedUrl) => {
    // upload cropped blob via existing backend /ocr and Puter pipeline
    (async () => {
      setMessage('Processing cropped image...');
      try {
        const formData = new FormData();
        formData.append('file', blob, 'crop.png');
        const uploadResponse = await fetch(`${API_BASE}/ocr`, { method: 'POST', body: formData });
        const uploadData = await uploadResponse.json();
        const dataUrl = uploadData.data_url;
        if (!window.puter) throw new Error('Puter not loaded');
        const extracted = await window.puter.ai.chat('Extract all the text from this image and return it as a paragraph. Only return the text, nothing else.', dataUrl, { model: 'gpt-5-nano' });

        // append to per-question storage
        const q = getQuestion(selectedQ) || { questionNumber: selectedQ, questionType: 'subjective', questionText: '', ocrText: '', uploads: [] };
        const newOcrText = (q.ocrText ? q.ocrText + '\n' : '') + extracted;
        q.ocrText = newOcrText;
        q.uploads = q.uploads || [];
        const uploadEntry = { id: Date.now(), name: 'crop.png', dataUrl: croppedUrl };
        q.uploads.push(uploadEntry);

        // Evaluate the extracted answer using Puter AI based on question metadata
        let evaluation = null;
        try {
          const maxMarks = q.maxMarks || 10;
          const prompt = `You are an experienced exam evaluator.\nQuestion:\n${q.questionText || ''}\n\nModel answer / answer key:\n${q.answerKey || ''}\n\nStudent answer:\n${extracted}\n\nInstructions: Assign a numeric score out of ${maxMarks} and provide a short justification (1-2 sentences). Respond with ONLY a JSON object exactly in this form: {"marks": <number>, "maxMarks": <number>, "justification": "..."}`;

          // Call Puter chat with prompt only (avoid passing explicit null which can crash cross-origin script)
          const evalResp = await window.puter.ai.chat(prompt, { model: 'gpt-5-nano' });
          try {
            evaluation = JSON.parse(evalResp);
          } catch (e) {
            // try to extract JSON substring
            const m = evalResp.match(/\{[\s\S]*\}/);
            if (m) evaluation = JSON.parse(m[0]);
            else throw e;
          }
        } catch (e) {
          console.warn('Evaluation failed, defaulting to empty evaluation', e);
        }

        if (evaluation) {
          q.lastEvaluation = {
            uploadId: uploadEntry.id,
            marks: evaluation.marks,
            maxMarks: evaluation.maxMarks || q.maxMarks || 10,
            justification: evaluation.justification || '',
            extractedText: extracted
          };
        } else {
          q.lastEvaluation = {
            uploadId: uploadEntry.id,
            marks: null,
            maxMarks: q.maxMarks || 10,
            justification: '',
            extractedText: extracted
          };
        }

        addOrUpdateQuestion(q);

        // update UI
        onSetExtractedText(q.ocrText);
        setMessage('Cropped image processed, evaluated, and appended to question.');
      } catch (e) {
        console.error(e);
        setMessage('Error processing image: ' + e.message);
      }
    })();
  };

  const handleSelectFileForCrop = (item) => {
    setCurrentPreview(item);
  };

  const dataUrlToBlob = async (dataUrl) => {
    const res = await fetch(dataUrl);
    return await res.blob();
  };

  const extractTextFromDataUrl = async (dataUrl, fileName = 'upload.png') => {
    const blob = await dataUrlToBlob(dataUrl);
    const formData = new FormData();
    formData.append('file', blob, fileName);
    const uploadResponse = await fetch(`${API_BASE}/ocr`, { method: 'POST', body: formData });
    const uploadData = await uploadResponse.json();
    const ocrDataUrl = uploadData.data_url;
    if (!window.puter) throw new Error('Puter not loaded');
    const extracted = await window.puter.ai.chat('Extract all the text from this image and return it as a paragraph. Only return the text, nothing else.', ocrDataUrl, { model: 'gpt-5-nano' });
    return extracted;
  };

  // Evaluate the current selected question's OCR text using Puter
  const handleEvaluateQuestion = async () => {
    if (!selectedQ) {
      setMessage('Select a question first');
      return;
    }
    const q = getQuestion(selectedQ);
    if (!q) {
      setMessage('Question not found');
      return;
    }
    if (!window.puter) {
      setMessage('Puter not loaded');
      return;
    }

    setMessage('Evaluating answer...');
    try {
      // If no OCR text yet, extract from uploaded full images (no cropping required)
      if (!q.ocrText || !q.ocrText.trim()) {
        if (!files || files.length === 0) {
          setMessage('No extracted text found. Upload images or crop first.');
          return;
        }

        let combinedText = '';
        for (const f of files) {
          const extracted = await extractTextFromDataUrl(f.dataUrl, f.name || 'upload.png');
          combinedText += (combinedText ? '\n' : '') + extracted;
        }

        q.ocrText = combinedText;
        addOrUpdateQuestion(q);
        onSetExtractedText(combinedText);
      }

      const maxMarks = q.maxMarks || 10;
      const prompt = `You are an experienced exam evaluator.\nQuestion:\n${q.questionText || ''}\n\nModel answer / answer key:\n${q.answerKey || ''}\n\nStudent answer:\n${q.ocrText}\n\nInstructions: Assign a numeric score out of ${maxMarks} and provide a short justification (1-2 sentences). Respond with ONLY a JSON object exactly in this form: {"marks": <number>, "maxMarks": <number>, "justification": "..."}`;

      const evalResp = await window.puter.ai.chat(prompt, { model: 'gpt-5-nano' });
      let evaluation = null;
      try {
        evaluation = JSON.parse(evalResp);
      } catch (e) {
        const m = evalResp.match(/\{[\s\S]*\}/);
        if (m) evaluation = JSON.parse(m[0]);
        else throw e;
      }

      q.lastEvaluation = {
        uploadId: q.uploads && q.uploads.length ? q.uploads[q.uploads.length - 1].id : Date.now(),
        marks: evaluation.marks,
        maxMarks: evaluation.maxMarks || maxMarks,
        justification: evaluation.justification || '',
        extractedText: q.ocrText
      };

      addOrUpdateQuestion(q);
      setMessage('Evaluation complete. Check the marks box to adjust and save feedback if needed.');
    } catch (e) {
      console.error(e);
      setMessage('Evaluation failed: ' + (e.message || e));
    }
  };

  return (
    <div style={{ padding: 12 }}>
      <h3>Question Uploader</h3>
      <div style={{ marginBottom: 8 }}>
        <label>Select Question</label>
        <select value={selectedQ} onChange={(e) => setSelectedQ(e.target.value)}>
          <option value="">-- select --</option>
          {questions.map((q) => (
            <option key={q.questionNumber} value={q.questionNumber}>{q.questionNumber} - {q.questionText.slice(0,40)}</option>
          ))}
        </select>
      </div>

      <div style={{ marginBottom: 8 }}>
        <label>Upload images for selected question (multiple)</label>
        <input type="file" accept="image/*" multiple onChange={handleFiles} />
        <div style={{ marginTop: 8 }}>
          <button type="button" onClick={handleEvaluateQuestion} disabled={!selectedQ}>Evaluate Answer for Selected Question</button>
        </div>
      </div>

      <div style={{ display: 'flex', gap: 12 }}>
        <div style={{ flex: 1 }}>
          <h4>Uploaded images</h4>
          {files.map((f, i) => (
            <div key={i} style={{ marginBottom: 8 }}>
              <img src={f.dataUrl} alt={f.name} style={{ maxWidth: 150 }} />
              <div>
                <button onClick={() => handleSelectFileForCrop(f)}>Crop</button>
              </div>
            </div>
          ))}
        </div>

        <div style={{ flex: 2 }}>
          <h4>Crop / Preview</h4>
          {currentPreview ? (
            <>
            <ImageCropper dataUrl={currentPreview.dataUrl} onCrop={handleCropResult} />
            {/* Show evaluation if available for selected question */}
            {selectedQ && (() => {
              const q = getQuestion(selectedQ);
              if (!q || !q.lastEvaluation) return null;
              const ev = q.lastEvaluation;
              return (
                <div style={{ marginTop: 12, border: '1px solid #ddd', padding: 8 }}>
                  <div><strong>Marks:</strong> <input type="number" defaultValue={ev.marks ?? ''} id={`marks-${ev.uploadId}`} style={{ width: 80 }} /></div>
                  <div style={{ marginTop: 8 }}><strong>Justification:</strong><div><textarea id={`just-${ev.uploadId}`} defaultValue={ev.justification} style={{ width: '100%', minHeight: 60 }} /></div></div>
                  <div style={{ marginTop: 8 }}>
                    <button onClick={async () => {
                      // send feedback when marks edited
                      const input = document.getElementById(`marks-${ev.uploadId}`);
                      const corrected = parseFloat(input.value);
                      if (isNaN(corrected)) {
                        setMessage('Please enter a numeric mark');
                        return;
                      }
                      try {
                        // update local state
                        const q2 = getQuestion(selectedQ);
                        const prev = q2.lastEvaluation.marks;
                        q2.lastEvaluation.marks = corrected;
                        addOrUpdateQuestion(q2);

                        // notify backend for training/feedback storage
                        await fetch(`${API_BASE}/feedback`, {
                          method: 'POST',
                          headers: { 'Content-Type': 'application/json' },
                          body: JSON.stringify({
                            questionNumber: selectedQ,
                            uploadId: ev.uploadId,
                            previousMarks: prev,
                            correctedMarks: corrected,
                            justification: (document.getElementById(`just-${ev.uploadId}`)?.value) || ev.justification || '',
                            extractedText: ev.extractedText || ''
                          })
                        });

                        setMessage('Mark updated and feedback sent to backend.');
                      } catch (e) {
                        console.error(e);
                        setMessage('Failed to send feedback: ' + e.message);
                      }
                    }}>Save corrected mark</button>
                  </div>
                </div>
              );
            })()}
            </>
          ) : (
            <div>Select an image to crop</div>
          )}
          {/* Always show latest evaluation summary for selected question (if any) */}
          {selectedQ && (() => {
            const q = getQuestion(selectedQ);
            if (!q || !q.lastEvaluation) return null;
            const ev = q.lastEvaluation;
            return (
              <div style={{ marginTop: 12, border: '1px solid #ccc', padding: 8 }}>
                <h4>Latest Evaluation</h4>
                <div><strong>Marks:</strong> {ev.marks ?? '—'} / {ev.maxMarks}</div>
                <div style={{ marginTop: 8 }}><strong>Justification:</strong><div style={{ border: '1px solid #eee', padding: 8 }}>{ev.justification || '—'}</div></div>
                <div style={{ marginTop: 8 }}>
                  <button onClick={handleEvaluateQuestion}>Re-evaluate</button>
                </div>
              </div>
            );
          })()}
          {message && <div style={{ marginTop: 8 }}>{message}</div>}
        </div>
      </div>
    </div>
  );
}
